mapper.delete:
DELETE FROM bank_process_accounting_posted
WHERE tenant_id = #{tenantId}
  AND posted_date BETWEEN #{fromDate} AND #{toDate}
  AND outcome = 'SKIPPED'

mapper.select:
SELECT COUNT(*)
FROM bank_process_accounting_posted
WHERE tenant_id = #{tenantId}
  AND bank_process_id = #{bankProcessId}
  AND outcome = 'POSTED'
  AND period_type <> 'COMPENSATION'
